module sr_latch (
    input wire clk,
    input wire S,
    input wire R,
    output reg obf_Q
);

    always @(posedge clk) begin
        if (S && !R) 
            obf_Q <= 1'b1; // Set
        else if (!S && R) 
            obf_Q <= 1'b0; // Reset
        // If S=0 and R=0, obf_Q remains unchanged
    end
endmodule
